import axios from 'axios';

// Create a new advisory
const createAdvisory = async (advisoryData, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.post('/api/advisory', advisoryData, config);
  return response.data;
};

// Get user advisories
const getAdvisories = async (token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.get('/api/advisory', config);
  return response.data;
};

// Get advisory by ID
const getAdvisoryById = async (advisoryId, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.get(`/api/advisory/${advisoryId}`, config);
  return response.data;
};

// Delete advisory
const deleteAdvisory = async (advisoryId, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.delete(`/api/advisory/${advisoryId}`, config);
  return response.data;
};

const advisoryService = {
  createAdvisory,
  getAdvisories,
  getAdvisoryById,
  deleteAdvisory,
};

export default advisoryService;
